def _planner_response(
    *,
    text: str,
    tool_name: str,
    args: dict | None = None,
    call_id: str,
    thought: str | None = None,
) -> LlmResponse:
    parts = []
    if thought is not None:
        parts.append(
            types.Part(
                text=thought,
                thought=True,
                thought_signature=f"{call_id}-signature".encode("utf-8"),
            )
        )
    parts.extend(
        [
            types.Part(text=text),
            types.Part(
                function_call=types.FunctionCall(
                    id=call_id,
                    name=tool_name,
                    args=args or {},
                )
            ),
        ]
    )
    return LlmResponse(
        content=types.Content(
            role="model",
            parts=parts,
        ),
        partial=False,
    )


